import sys
input = sys.stdin.readline

n, k = map(int, input().split())
a = list(map(int, input().split()))

s = []
b = []

for i in a:
    if not s:
        s.append(i)
    else:
        if i > s[-1]:
            b.append(s.pop())
            while s and i > s[-1]:
                b.append(s.pop())
            s.append(i)
        else:
            s.append(i)

while s:
    b.append(s.pop())

if len(b) == n:
    print(*b)
else:
    print(-1)
